export function getSchoolsByRegion(region: RegionSlug): School[] {
  return schools.filter(s => s.region === region)
}

export function getSchoolsByRegionAndType(region: RegionSlug, type: SchoolType): School[] {
  return schools.filter(s => s.region === region && s.type === type)
}

export function getSchoolBySlug(slug: string): School | undefined {
  return schools.find(s => s.slug === slug)
}

export function getAllSchoolSlugs(): string[] {
  return schools.map(s => s.slug)
}

export function formatPrice(price: number): string {
  return price.toLocaleString('ru-RU') + ' ₽/мес'
}

