export const featureSlugs: FeatureSlug[] = featureMetas.map(f => f.slug)

export function getFeatureBySlug(slug: string): FeatureMeta | undefined {
  return featureMetas.find(f => f.slug === slug)
}

export function getSchoolsByFeature(featureSlug: FeatureSlug, region?: RegionSlug): School[] {
  const meta = getFeatureBySlug(featureSlug)
  if (!meta) return []
  return schools.filter(s => {
    if (region && s.region !== region) return false
    const haystack = [s.name, s.description, s.fullDescription ?? '', ...s.features].join(' ').toLowerCase()
    return meta.keywords.some(kw => haystack.includes(kw.toLowerCase()))
  })
}

