export const languageSlugs: LanguageSlug[] = languageMetas.map(l => l.slug)

export function getLanguageBySlug(slug: string): LanguageMeta | undefined {
  return languageMetas.find(l => l.slug === slug)
}

export function getSchoolsByLanguage(langSlug: LanguageSlug, region?: RegionSlug): School[] {
  const meta = getLanguageBySlug(langSlug)
  if (!meta) return []
  return schools.filter(s => {
    if (region && s.region !== region) return false
    // Сначала проверяем поле languages (если заполнено)
    if (s.languages && s.languages.includes(langSlug)) return true
    // Иначе — keyword matching по тексту
    const haystack = [s.name, s.description, s.fullDescription ?? '', ...s.features].join(' ').toLowerCase()
    return meta.keywords.some(kw => haystack.includes(kw.toLowerCase()))
  })
}

